diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
index fdef49e310f8..5d66e28b9d66 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
@@ -842,6 +842,34 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
       return new ICmpInst(ICmpInst::ICMP_NE, And, Zero);
     }

+    // trunc (lshr C, X) to i1 --> X == log2(C), where C is pow2
+    // trunc (lshr (C-1), X) to i1 --> X <u log2(C), where C is pow2
+    if (match(Src, m_LShr(m_APInt(C1), m_Value(X)))) {
+      if (C1->isPowerOf2()) {
+        unsigned Log2C = C1->exactLogBase2();
+        Constant *CmpC = ConstantInt::get(X->getType(), Log2C);
+        return new ICmpInst(ICmpInst::ICMP_EQ, X, CmpC);
+      }
+      if ((*C1 + 1).isPowerOf2()) {
+        unsigned Log2C = (*C1 + 1).exactLogBase2();
+        Constant *CmpC = ConstantInt::get(X->getType(), Log2C);
+        return new ICmpInst(ICmpInst::ICMP_ULT, X, CmpC);
+      }
+    }
+    // trunc (ashr C, X) to i1 --> X == log2(C), where C is positive pow2
+    // trunc (ashr (C-1), X) to i1 --> X <u log2(C), where C is positive pow2
+    if (match(Src, m_AShr(m_APInt(C1), m_Value(X)))) {
+      if (C1->isNonNegative() && C1->isPowerOf2()) {
+        unsigned Log2C = C1->exactLogBase2();
+        Constant *CmpC = ConstantInt::get(X->getType(), Log2C);
+        return new ICmpInst(ICmpInst::ICMP_EQ, X, CmpC);
+      }
+      if (C1->isNonNegative() && (*C1 + 1).isPowerOf2()) {
+        unsigned Log2C = (*C1 + 1).exactLogBase2();
+        Constant *CmpC = ConstantInt::get(X->getType(), Log2C);
+        return new ICmpInst(ICmpInst::ICMP_ULT, X, CmpC);
+      }
+    }
     {
       const APInt *C;
       if (match(Src, m_Shl(m_APInt(C), m_Value(X))) && (*C)[0] == 1) {

